What do you think about the following workaround to handle `__slots__` classes?
```
class slots_cached_property(object):
    cached_attr_prefix = 'cached_'

    def __init__(self, func):
        self.func = func

    def __get__(self, obj, cls):
        cached_attr_name = self.cached_attr_prefix + self.func.__name__

        if not hasattr(obj, cached_attr_name):
            value = self.func(obj)
            setattr(obj, cached_attr_name, value)
        return getattr(obj, cached_attr_name)


class Foo(object):
    __slots__ = 'cached_sum', 'items'

    def __init__(self, items):
        self.items = items

    @slots_cached_property
    def sum(self):
        return sum(self.items)


foo = Foo([1, 2, 3])
print foo.sum
```

