The following is my test code.

```
import numpy as np
import math


def code_from_rth (center, size, torus, pos_1, pos_2):
    pos_1 = np.array(pos_1)
    pos_2 = np.array(pos_2)
    if torus:
        pos_1 = np.abs(pos_1 - center) % size
        pos_2 = np.abs(pos_2 - center) % size
    return np.linalg.norm(pos_1 - pos_2)


def code_from_clmerlos (center, size, torus, pos_1, pos_2):
    pos_1 = np.array(pos_1)
    pos_2 = np.array(pos_2)
    dist_1 = np.linalg.norm(pos_1 - pos_2)
    if torus:
        pos_1 = (pos_1 - center) % size
        pos_2 = (pos_2 - center) % size
    dist_2 = np.linalg.norm(pos_1 - pos_2)
    return min(dist_1, dist_2)


def code_from_mesa_077(center, size, torus, pos_1, pos_2):
    x1, y1 = pos_1
    x2, y2 = pos_2
    if not torus:
        dx = x1 - x2
        dy = y1 - y2
    else:
        d_x = abs(x1 - x2)
        d_y = abs(y1 - y2)
        dx = min(d_x, size[0] - d_x)
        dy = min(d_y, size[1] - d_y)
    return math.sqrt(dx ** 2 + dy ** 2)


if __name__ == '__main__':
    center = np.array((20, -5))
