I just want to know what will happen if I created `ClientSession` outside of coroutine and manually close it without using `async with`?

This is a simple example: 
```
import aiohttp
import asyncio

Queue = asyncio.Queue

class MyAio:
    session = aiohttp.ClientSession()

    
    def __init__(self, urls:iter):

        self.workQueue = Queue()

        for i in urls:
            self.workQueue.put_nowait(i)

    def __del__(self):
        if not self.session.closed:
            if self.session._connector_owner:
                self.session._connector.close()
            self.session._connector = None

    async def getGithubEvent(self, url):
        result = await self.session.get(url)
        return await result.text(encoding='utf-8')

    async def fetch(self, url):
        text = await self.getGithubEvent(url)
        print(text[:10])

    async def worker(self):
        try:
            while 1:
                url = await self.workQueue.get()
                await self.fetch(url)
                self.workQueue.task_done()
        except asyncio.CancelledError:
            pass

    async def run(self):
        workers = [asyncio.Task(self.worker()) for _ in range(3)]
        asyncio.gather(*workers)

        await self.workQueue.join()

        for i in workers:
            i.cancel()

    def start(self):
        try:
            event_loop = asyncio.get_event_loop()
            event_loop.run_until_complete(self.run())
        except KeyboardInterrupt:
            for task in asyncio.Task.all_tasks():
                task.cancel()
                event_loop.run_forever()
        finally:
            event_loop.close()

test = MyAio(['https://api.github.com/events']*9)
test.start()
```

